            test_cases=[
                ([1, 2, 3, 2, 2], 2, 3),
                ([5, 5, 5], 5, 3),
                ([1, 2, 3], 4, 0),
                ([], 1, 0),
            ],
            correct_solution="def solution(lst, target):\n    return lst.count(target)",
