def run_ablation_experiment(dataset_name: str, problems: List[ProgrammingProblem]):
    print(f"\n{'=' * 80}")
    print(f"Ablation Study: {dataset_name}")
    print(f"{'=' * 80}")

    failure_library = build_failure_library(problems)
    total_patterns = sum(len(patterns) for patterns in failure_library.values())
    print(
        f"Built failure library with {total_patterns} patterns across {len(failure_library)} categories"
    )

    # Store ground truth
    for problem in problems:
        experiment_data["baseline_category_specific"][dataset_name][
            "ground_truth"
        ].append(
            {
                "problem_id": problem.problem_id,
                "description": problem.description,
                "correct_solution": problem.correct_solution,
                "complexity": problem.complexity,
            }
        )
        experiment_data["ablation_random_retrieval"][dataset_name][
            "ground_truth"
        ].append(
            {
                "problem_id": problem.problem_id,
                "description": problem.description,
                "correct_solution": problem.correct_solution,
                "complexity": problem.complexity,
            }
        )

    # Test configurations
    configs = [
        {
            "initial_success_rate": 0.60,
            "refinement_success_rate": 0.65,
            "max_stages": 1,
            "retrieval_k": 1,
        },
        {
            "initial_success_rate": 0.60,
            "refinement_success_rate": 0.70,
            "max_stages": 2,
            "retrieval_k": 2,
        },
        {
            "initial_success_rate": 0.60,
            "refinement_success_rate": 0.75,
            "max_stages": 3,
            "retrieval_k": 2,
        },
    ]

    n_trials = 20

    baseline_results_per_config = []
    ablation_results_per_config = []
    baseline_analyses = []
    ablation_analyses = []

    for epoch, config in enumerate(configs):
        print(f"\n[{epoch+1}/{len(configs)}] Config: {config}")

        # Baseline: Category-specific retrieval
        print("  Running BASELINE (Category-Specific Retrieval)...")
        baseline_trial_scores = []
        baseline_trial_analyses = []
        for trial in range(n_trials):
            pass_at_1, analysis = evaluate_multi_stage(
                problems, failure_library, config, use_category_retrieval=True
            )
            baseline_trial_scores.append(pass_at_1)
            baseline_trial_analyses.append(analysis)

        baseline_mean = np.mean(baseline_trial_scores)
        baseline_std = np.std(baseline_trial_scores)
        baseline_results_per_config.append(baseline_trial_scores)
        baseline_analyses.append(baseline_trial_analyses[0])

        print(f"    Baseline Pass@1: {baseline_mean:.3f} ± {baseline_std:.3f}")

        # Ablation: Random retrieval
        print("  Running ABLATION (Random Retrieval)...")
        ablation_trial_scores = []
        ablation_trial_analyses = []
        for trial in range(n_trials):
            pass_at_1, analysis = evaluate_multi_stage(
                problems, failure_library, config, use_category_retrieval=False
            )
            ablation_trial_scores.append(pass_at_1)
            ablation_trial_analyses.append(analysis)

        ablation_mean = np.mean(ablation_trial_scores)
        ablation_std = np.std(ablation_trial_scores)
        ablation_results_per_config.append(ablation_trial_scores)
        ablation_analyses.append(ablation_trial_analyses[0])

        print(f"    Ablation Pass@1: {ablation_mean:.3f} ± {ablation_std:.3f}")

        performance_drop = baseline_mean - ablation_mean
        relative_drop = (
            (performance_drop / baseline_mean * 100) if baseline_mean > 0 else 0
        )
        print(f"    Performance Drop: {performance_drop:.3f} ({relative_drop:.1f}%)")

        # Store metrics for baseline
        experiment_data["baseline_category_specific"][dataset_name]["metrics"][
            "train"
        ].append(baseline_mean)
        experiment_data["baseline_category_specific"][dataset_name]["metrics"][
            "val"
        ].append(baseline_mean)
        experiment_data["baseline_category_specific"][dataset_name]["losses"][
            "train"
        ].append(1 - baseline_mean)
        experiment_data["baseline_category_specific"][dataset_name]["losses"][
            "val"
        ].append(1 - baseline_mean)
        print(f"Epoch {epoch} [Baseline]: validation_loss = {1 - baseline_mean:.4f}")

        experiment_data["baseline_category_specific"][dataset_name]["predictions"][
            f"config_{epoch}"
        ] = {
            "config": config,
            "scores": baseline_trial_scores,
            "mean": float(baseline_mean),
            "std": float(baseline_std),
            "analysis": {
                "avg_stages": float(baseline_trial_analyses[0]["avg_stages"]),
                "correction_rates": {
                    k: float(v)
                    for k, v in baseline_trial_analyses[0]["correction_rates"].items()
                },
            },
        }

        # Store metrics for ablation
        experiment_data["ablation_random_retrieval"][dataset_name]["metrics"][
            "train"
        ].append(ablation_mean)
        experiment_data["ablation_random_retrieval"][dataset_name]["metrics"][
            "val"
        ].append(ablation_mean)
        experiment_data["ablation_random_retrieval"][dataset_name]["losses"][
            "train"
        ].append(1 - ablation_mean)
        experiment_data["ablation_random_retrieval"][dataset_name]["losses"][
            "val"
        ].append(1 - ablation_mean)
        print(f"Epoch {epoch} [Ablation]: validation_loss = {1 - ablation_mean:.4f}")

        experiment_data["ablation_random_retrieval"][dataset_name]["predictions"][
            f"config_{epoch}"
        ] = {
            "config": config,
            "scores": ablation_trial_scores,
            "mean": float(ablation_mean),
            "std": float(ablation_std),
            "performance_drop": float(performance_drop),
            "relative_drop_percent": float(relative_drop),
            "analysis": {
                "avg_stages": float(ablation_trial_analyses[0]["avg_stages"]),
                "correction_rates": {
                    k: float(v)
                    for k, v in ablation_trial_analyses[0]["correction_rates"].items()
                },
            },
        }

    experiment_data["baseline_category_specific"][dataset_name][
        "stage_analysis"
    ] = baseline_analyses
    experiment_data["ablation_random_retrieval"][dataset_name][
        "stage_analysis"
    ] = ablation_analyses

    return (
        configs,
        baseline_results_per_config,
        ablation_results_per_config,
        baseline_analyses,
        ablation_analyses,
    )


