def create_ablation_visualizations(dataset_name: str, results_tuple: Tuple):
    (
        configs,
        baseline_results_per_config,
        ablation_results_per_config,
        baseline_analyses,
        ablation_analyses,
    ) = results_tuple

    fig, axes = plt.subplots(2, 2, figsize=(14, 10))

    baseline_means = [np.mean(scores) for scores in baseline_results_per_config]
    ablation_means = [np.mean(scores) for scores in ablation_results_per_config]
    config_labels = [f"C{i+1}\n({c['max_stages']}st)" for i, c in enumerate(configs)]

    # Plot 1: Pass@1 comparison
    ax1 = axes[0, 0]
    x = np.arange(len(configs))
    width = 0.35
    ax1.bar(
        x - width / 2,
        baseline_means,
        width,
        label="Category-Specific",
        alpha=0.8,
        color="blue",
    )
    ax1.bar(
        x + width / 2,
        ablation_means,
        width,
        label="Random Retrieval",
        alpha=0.8,
        color="red",
    )
    ax1.set_xlabel("Configuration", fontsize=11)
    ax1.set_ylabel("Pass@1 Rate", fontsize=11)
    ax1.set_title(
        f"{dataset_name}: Baseline vs Ablation", fontsize=12, fontweight="bold"
    )
    ax1.set_xticks(x)
    ax1.set_xticklabels(config_labels)
    ax1.legend()
    ax1.grid(axis="y", alpha=0.3)

    # Plot 2: Performance drop
    ax2 = axes[0, 1]
    performance_drops = [
        baseline_means[i] - ablation_means[i] for i in range(len(configs))
    ]
    relative_drops = [
        (
            (baseline_means[i] - ablation_means[i]) / baseline_means[i] * 100
            if baseline_means[i] > 0
            else 0
        )
        for i in range(len(configs))
    ]
    bars = ax2.bar(range(len(configs)), relative_drops, alpha=0.7, color="orange")
    ax2.set_xticks(range(len(configs)))
    ax2.set_xticklabels(config_labels)
    ax2.set_xlabel("Configuration", fontsize=11)
    ax2.set_ylabel("Performance Drop (%)", fontsize=11)
    ax2.set_title(
        f"{dataset_name}: Impact of Removing Category-Specific Retrieval",
        fontsize=12,
        fontweight="bold",
    )
    ax2.axhline(y=0, color="black", linestyle="-", linewidth=0.5)
    ax2.grid(axis="y", alpha=0.3)

    # Plot 3: Error correction rates comparison
    ax3 = axes[1, 0]
    if baseline_analyses and "correction_rates" in baseline_analyses[-1]:
        categories = list(baseline_analyses[-1]["correction_rates"].keys())
        if categories:
            baseline_rates = [
                baseline_analyses[-1]["correction_rates"].get(cat, 0)
                for cat in categories
            ]
            ablation_rates = [
                ablation_analyses[-1]["correction_rates"].get(cat, 0)
                for cat in categories
            ]

            x = np.arange(len(categories))
            width = 0.35
            ax3.bar(
                x - width / 2,
                baseline_rates,
                width,
                label="Category-Specific",
                alpha=0.7,
                color="blue",
            )
            ax3.bar(
                x + width / 2,
                ablation_rates,
                width,
                label="Random Retrieval",
                alpha=0.7,
                color="red",
            )

            ax3.set_xlabel("Error Category", fontsize=11)
            ax3.set_ylabel("Correction Rate", fontsize=11)
            ax3.set_title(
                f"{dataset_name}: Correction Rates by Category",
                fontsize=12,
                fontweight="bold",
            )
            ax3.set_xticks(x)
            ax3.set_xticklabels(categories, rotation=45, ha="right")
            ax3.legend()
            ax3.grid(axis="y", alpha=0.3)

    # Plot 4: Stage utilization
    ax4 = axes[1, 1]
    baseline_stages = [baseline_analyses[i]["avg_stages"] for i in range(len(configs))]
    ablation_stages = [ablation_analyses[i]["avg_stages"] for i in range(len(configs))]
    ax4.plot(
        range(len(configs)),
        baseline_stages,
        marker="o",
        linewidth=2,
        markersize=8,
        label="Category-Specific",
        color="blue",
    )
    ax4.plot(
        range(len(configs)),
        ablation_stages,
        marker="s",
        linewidth=2,
        markersize=8,
        label="Random Retrieval",
        color="red",
    )
    ax4.set_xlabel("Configuration", fontsize=11)
    ax4.set_ylabel("Average Refinement Stages", fontsize=11)
    ax4.set_title(f"{dataset_name}: Stage Utilization", fontsize=12, fontweight="bold")
    ax4.set_xticks(range(len(configs)))
    ax4.set_xticklabels(config_labels)
    ax4.legend()
    ax4.grid(alpha=0.3)

    plt.tight_layout()
    plt.savefig(
        os.path.join(working_dir, f"ablation_{dataset_name}.png"),
        dpi=150,
        bbox_inches="tight",
    )
    plt.close()
    print(f"Ablation visualization saved for {dataset_name}")


