ERROR_CATEGORIES = {
    "syntax": ["SyntaxError", "IndentationError", "NameError"],
    "logic": ["AssertionError", "failed_test"],
    "boundary": ["IndexError", "off_by_one"],
    "api": ["AttributeError", "TypeError"],
    "algorithmic": ["timeout", "wrong_algorithm"],
}


def classify_error(error_msg: str, test_results: List[bool]) -> str:
    error_lower = error_msg.lower()
    for category, keywords in ERROR_CATEGORIES.items():
        for keyword in keywords:
            if keyword.lower() in error_lower:
                return category
    if not all(test_results):
        failed_ratio = sum(1 for t in test_results if not t) / len(test_results)
        if failed_ratio > 0.8:
            return "algorithmic"
        elif failed_ratio < 0.3:
            return "boundary"
        else:
            return "logic"
    return "unknown"


def estimate_problem_complexity(problem) -> float:
    score = 0.0
    desc_length = len(problem.description.split())
    if desc_length > 30:
        score += 0.3
    elif desc_length > 15:
        score += 0.15
    num_tests = len(problem.test_cases)
    if num_tests > 3:
        score += 0.2
    elif num_tests > 2:
        score += 0.1
    if any(
        kw in problem.description.lower()
        for kw in ["algorithm", "optimal", "efficient", "complexity"]
    ):
        score += 0.3
    if problem.dataset_type == "code_contests":
        score += 0.2
    return min(score, 1.0)


class ProgrammingProblem:
    def __init__(
        self,
        problem_id: str,
        description: str,
        test_cases: List[Tuple],
        correct_solution: str,
        common_errors: List[str],
        dataset_type: str = "synthetic",
    ):
        self.problem_id = problem_id
        self.description = description
        self.test_cases = test_cases
        self.correct_solution = correct_solution
        self.common_errors = common_errors
        self.dataset_type = dataset_type
        self.complexity = estimate_problem_complexity(self)


class FailurePattern:
    def __init__(
        self,
        error_type: str,
        error_category: str,
        error_message: str,
        failed_code: str,
        corrected_code: str,
        problem_context: str,
    ):
        self.error_type = error_type
        self.error_category = error_category
        self.error_message = error_message
        self.failed_code = failed_code
        self.corrected_code = corrected_code
        self.problem_context = problem_context


def create_synthetic_dataset():
    problems = []
    problems.append(
        ProgrammingProblem(
            "sum_list",
            "Write a function that returns the sum of all numbers in a list.",
            [([1, 2, 3], 6), ([10, -5, 3], 8), ([], 0), ([5], 5)],
            "def solution(lst):\n    return sum(lst)",
            ["off_by_one", "null_handling", "type_error"],
            "synthetic",
        )
    )
    problems.append(
        ProgrammingProblem(
            "find_max",
            "Write a function that returns the maximum element in a non-empty list.",
            [([1, 5, 3], 5), ([-10, -5, -20], -5), ([42], 42), ([1, 1, 1], 1)],
            "def solution(lst):\n    return max(lst)",
            ["boundary_error", "comparison_error"],
            "synthetic",
        )
    )
    problems.append(
        ProgrammingProblem(
            "count_occurrences",
            "Write a function that counts how many times a target value appears in a list.",
            [([1, 2, 3, 2, 2], 2, 3), ([5, 5, 5], 5, 3), ([1, 2, 3], 4, 0), ([], 1, 0)],
            "def solution(lst, target):\n    return lst.count(target)",
            ["null_handling", "logic_error"],
            "synthetic",
        )
    )
    problems.append(
        ProgrammingProblem(
            "reverse_string",
            "Write a function that reverses a string.",
            [("hello", "olleh"), ("a", "a"), ("", ""), ("12345", "54321")],
            "def solution(s):\n    return s[::-1]",
            ["index_error", "type_error"],
            "synthetic",
        )
    )
    return problems


def load_code_contests_dataset():
    print("\nLoading code_contests dataset...")
    try:
        dataset = load_dataset("deepmind/code_contests", split="test")
        problems = []
        for i, item in enumerate(dataset):
            if i >= 10:
                break
            description = item.get("description", "")[:250]
            if not description:
                continue
            public_tests = item.get("public_tests", {})
            if public_tests and "input" in public_tests and "output" in public_tests:
                inputs = public_tests["input"]
                outputs = public_tests["output"]
                test_cases = []
                for inp, out in zip(inputs[:3], outputs[:3]):
                    if inp is not None and out is not None:
                        test_cases.append((str(inp).strip(), str(out).strip()))
                if test_cases:
                    expected_output = test_cases[0][1] if test_cases else ""
                    problems.append(
                        ProgrammingProblem(
                            f"code_contests_{i}",
                            description,
                            test_cases,
                            f"def solution(inp):\n    return '{expected_output}'",
                            ["logic_error", "type_error", "boundary_error"],
                            "code_contests",
                        )
                    )
        if len(problems) < 5:
            return create_fallback_code_contests()
        print(f"Loaded {len(problems)} problems from code_contests")
        return problems[:8]
    except Exception as e:
        print(f"Error loading code_contests: {e}")
        return create_fallback_code_contests()


def create_fallback_code_contests():
    problems = []
    problems.append(
        ProgrammingProblem(
            "two_sum",
            "Given an array of integers and a target, return indices of two numbers that add up to target.",
            [([2, 7, 11, 15], 9, [0, 1]), ([3, 2, 4], 6, [1, 2])],
            "def solution(nums, target):\n    seen = {}\n    for i, num in enumerate(nums):\n        if target - num in seen:\n            return [seen[target - num], i]\n        seen[num] = i\n    return []",
            ["logic_error", "boundary_error"],
