        markersize=8,
        color="purple",
    )
    ax4.set_xlabel("Configuration", fontsize=11)
    ax4.set_ylabel("Average Refinement Stages", fontsize=11)
    ax4.set_title(f"{dataset_name}: Stage Utilization", fontsize=12, fontweight="bold")
    ax4.set_xticks(range(len(configs)))
